import './style.css';

    // Configuración general de diapositivas
    let currentSlide = 0;
    const slides = document.querySelectorAll('.slide');
    const totalSlides = slides.length;
    const prevBtn = document.getElementById('prev-btn');
    const nextBtn = document.getElementById('next-btn');
    const slideInd = document.getElementById('slide-ind');

    function changeSlide(direction) {
      // Remover clase active actual
      slides[currentSlide].classList.remove('active');
      if (direction === -1) {
        slides[currentSlide].classList.add('next');
      } else {
        slides[currentSlide].classList.add('prev');
      }

      currentSlide += direction;

      // Limitar límites
      if (currentSlide < 0) currentSlide = 0;
      if (currentSlide >= totalSlides) currentSlide = totalSlides - 1;

      // Mostrar nueva slide
      slides[currentSlide].className = 'slide active';

      // Actualizar UI
      slideInd.innerText = `${currentSlide + 1} / ${totalSlides}`;
      
      prevBtn.disabled = currentSlide === 0;
      nextBtn.disabled = currentSlide === totalSlides - 1;
      
      // Hook de cambio de slide
      if (typeof onSlideChange === 'function') {
        onSlideChange(currentSlide);
      }
    }

    // Funciones específicas del mapa de la slide 1
    function selectPin(company) {
      document.querySelectorAll('.info-card').forEach(card => {
        card.classList.remove('active-card');
      });
      document.querySelectorAll('.map-link-line').forEach(line => {
        line.style.opacity = '0.3';
      });
      document.querySelectorAll('.map-pin').forEach(pin => {
        pin.classList.remove('active-pin');
      });

      document.getElementById(`card-${company}`).classList.add('active-card');
      document.getElementById(`line-${company}`).style.opacity = '1.0';
      document.getElementById(`pin-${company}`).classList.add('active-pin');
    }

    // Funciones de la calculadora de la slide 3
    function adjustValue(fieldId, delta) {
      const input = document.getElementById(fieldId);
      let val = parseInt(input.value) || 0;
      val += delta;
      if (val < 0) val = 0;
      input.value = val;
      calculateCost();
    }

    function calculateCost() {
      const equipos = parseInt(document.getElementById('equipos').value) || 0;
      const servicios = parseInt(document.getElementById('servicios').value) || 0;
      const otros = parseInt(document.getElementById('otros').value) || 0;

      // Inversión acumulada en 5 años (60 meses)
      const total = equipos + (servicios * 12 * 5) + (otros * 12 * 5);

      // Formatear moneda Soles
      const formatter = new Intl.NumberFormat('es-PE', {
        style: 'currency',
        currency: 'PEN',
        minimumFractionDigits: 2
      });

      document.getElementById('calc-total').innerText = formatter.format(total).replace('PEN', 'S/.');
      
      // Mostrar ráfaga de preguntas
      const rafaga = document.getElementById('rafaga-panel');
      rafaga.style.display = 'flex';
    }

    // Modales de la slide 4
    function openModal(modalId) {
      document.getElementById(`modal-${modalId}`).style.display = 'flex';
    }

    function closeModal(modalId) {
      document.getElementById(`modal-${modalId}`).style.display = 'none';
    }

    // Cerrar modales clickeando fuera de ellos
    window.onclick = function(event) {
      if (event.target.classList.contains('modal-overlay')) {
        event.target.style.display = 'none';
      }
    }

    // State Variables del juego cognitivo
    let gameCurrentScreen = 1;
    let gameUserData = {
        mathSelectedNum: null,
        mathResult: 9,
        rabbitsCounted: 6, // Forced score
        poseSelected: '',
        mathStep: 1
    };

    // Whack-a-Rabbit variables
    let whackScore = 0;
    let whackTimerInterval;
    let whackTimer = 10;
    let whackActive = false;
    let rabbitTimeout;
    const whackSequence = ['P', 'P', 'I', 'P', 'I', 'P', 'P', 'I', 'I', 'P', 'I', 'P'];
    let sequenceIndex = 0;

    // Poses screen timer
    let poseTimerInterval;
    let poseTimer = 7;

    // Memorization test state
    let memoAnswers = {
        rabbits: '',
        math: '',
        pose: ''
    };

    // DOM Screens del juego
    let gameScreens;

    function initGameDOM() {
      gameScreens = {
          1: document.getElementById('screen1'),
          2: document.getElementById('screen2'),
          4: document.getElementById('screen4'),
          5: document.getElementById('screen5'),
          6: document.getElementById('screen6')
      };
    }

    function navigateToGameScreen(screenNumber) {
        if (!gameScreens) initGameDOM();
        gameScreens[gameCurrentScreen].classList.remove('active');
        gameScreens[screenNumber].classList.add('active');
        gameCurrentScreen = screenNumber;
        
        if (screenNumber === 4) {
            startPoseTimer();
        }
    }

    // --- PANTALLA 1: WHACK-A-RABBIT ---
    function initWhackGame() {
      const btnStartWhack = document.getElementById('btnStartWhack');
      const btnGoToScreen2 = document.getElementById('btnGoToScreen2');
      const scoreVal = document.getElementById('scoreVal');
      const whackTimerVal = document.getElementById('whackTimerVal');
      const holes = document.querySelectorAll('#slide-4 .hole');
      let currentHole = null;

      function randomHole() {
          const idx = Math.floor(Math.random() * holes.length);
          const hole = holes[idx];
          if (hole === currentHole) {
              return randomHole();
          }
          currentHole = hole;
          return hole;
      }

      function peep() {
          if (!whackActive) return;
          
          if (whackScore >= 6) {
              endWhackGame();
              return;
          }

          let type = 'P';
          if (sequenceIndex < whackSequence.length) {
              type = whackSequence[sequenceIndex];
              sequenceIndex++;
          }

          const time = type === 'P' ? (Math.random() * 400 + 500) : (Math.random() * 100 + 150);
          const hole = randomHole();
          const rabbit = hole.querySelector('.rabbit-target');
          
          rabbit.classList.add('up');
          
          rabbitTimeout = setTimeout(() => {
              rabbit.classList.remove('up');
              if (whackActive) setTimeout(peep, 50);
          }, time);
      }

      function endWhackGame() {
          whackActive = false;
          clearInterval(whackTimerInterval);
          clearTimeout(rabbitTimeout);
          
          whackScore = 6;
          scoreVal.innerText = whackScore;
          whackTimerVal.innerText = "0";
          
          document.querySelectorAll('#slide-4 .rabbit-target').forEach(r => r.classList.remove('up'));
          btnGoToScreen2.style.display = 'inline-block';
      }

      function startWhackGame() {
          btnStartWhack.style.display = 'none';
          whackScore = 0;
          whackTimer = 10;
          sequenceIndex = 0;
          scoreVal.innerText = whackScore;
          whackTimerVal.innerText = whackTimer;
          whackActive = true;
          
          peep();
          
          whackTimerInterval = setInterval(() => {
              if (!whackActive) return;
              whackTimer--;
              if (whackTimer > 0) {
                  whackTimerVal.innerText = whackTimer;
              } else {
                  whackTimerVal.innerText = "0";
                  clearInterval(whackTimerInterval);
              }
          }, 1000);
      }

      holes.forEach(hole => {
          hole.addEventListener('click', (e) => {
              if (!whackActive) return;
              const rabbit = hole.querySelector('.rabbit-target');
              if (rabbit.classList.contains('up')) {
                  if (whackScore < 6) {
                      whackScore++;
                      scoreVal.innerText = whackScore;
                  }
                  rabbit.classList.remove('up');
                  clearTimeout(rabbitTimeout);
                  
                  if (whackScore >= 6) {
                      endWhackGame();
                  } else {
                      setTimeout(peep, 50);
                  }
              }
          });
      });

      btnStartWhack.onclick = startWhackGame;
      btnGoToScreen2.onclick = () => {
          navigateToGameScreen(2);
      };
    }

    // --- PANTALLA 2: JUEGO MATEMÁTICO ---
    function initMathGame() {
      const mathGridNumbers = document.querySelector('#slide-4 .math-grid-numbers');
      const btnMathStep2 = document.getElementById('btnMathStep2');
      const btnMathStep3 = document.getElementById('btnMathStep3');
      const btnMathStep4 = document.getElementById('btnMathStep4');

      mathGridNumbers.onclick = (e) => {
          if (e.target.classList.contains('btn-math-num')) {
              Array.from(mathGridNumbers.children).forEach(el => el.classList.remove('selected'));
              e.target.classList.add('selected');
              gameUserData.mathSelectedNum = parseInt(e.target.getAttribute('data-num'), 10);
              
              setTimeout(() => {
                  document.getElementById('mathSlide1').classList.remove('active');
                  document.getElementById('mathSlide2').classList.add('active');
              }, 500);
          }
      };

      btnMathStep2.onclick = () => {
          document.getElementById('mathSlide2').classList.remove('active');
          document.getElementById('mathSlide3').classList.add('active');
      };

      btnMathStep3.onclick = () => {
          document.getElementById('mathSlide3').classList.remove('active');
          document.getElementById('mathSlide4').classList.add('active');
      };

      btnMathStep4.onclick = () => {
          navigateToGameScreen(4);
      };
    }

    // --- PANTALLA 4: ELECCIÓN DE POSE ---
    function startPoseTimer() {
        const poseTimerVal = document.getElementById('poseTimerVal');
        poseTimer = 7;
        poseTimerVal.innerText = poseTimer;
        
        poseTimerInterval = setInterval(() => {
            poseTimer--;
            poseTimerVal.innerText = poseTimer;
            
            if (poseTimer <= 0) {
                clearInterval(poseTimerInterval);
                selectPose('Pose X');
            }
        }, 1000);
    }

    function initPoseSelection() {
      const poseButtons = document.getElementById('poseButtons');
      poseButtons.onclick = (e) => {
          const card = e.target.closest('.pose-card');
          if (card) {
              clearInterval(poseTimerInterval);
              const poseName = card.getAttribute('data-pose');
              
              Array.from(poseButtons.children).forEach(el => el.classList.remove('selected'));
              card.classList.add('selected');
              
              setTimeout(() => {
                  selectPose(poseName);
              }, 300);
          }
      };
    }

    function selectPose(poseName) {
        gameUserData.poseSelected = poseName;
        navigateToGameScreen(5);
    }

    // --- PANTALLA 5: PRUEBA DE MEMORIZACIÓN ---
    function initMemoTest() {
      const memoGroup1 = document.getElementById('memoGroup1');
      const memoGroup2 = document.getElementById('memoGroup2');
      const memoGroup3 = document.getElementById('memoGroup3');
      const memoOutputVal = document.getElementById('memoOutputVal');
      const btnGoToExplanation = document.getElementById('btnGoToExplanation');

      function updateMemoOutput() {
          let outputText = '';
          if (memoAnswers.rabbits) {
              outputText += memoAnswers.rabbits;
          }
          if (memoAnswers.math) {
              outputText += memoAnswers.math;
          }
          if (memoAnswers.pose) {
              outputText += ' ' + memoAnswers.pose.toLowerCase();
          }
          memoOutputVal.value = outputText;
          
          if (memoAnswers.rabbits && memoAnswers.math && memoAnswers.pose) {
              btnGoToExplanation.disabled = false;
          }
      }

      memoGroup1.onclick = (e) => {
          if (e.target.classList.contains('btn-option')) {
              Array.from(memoGroup1.querySelector('.btn-options-container').children).forEach(el => el.classList.remove('selected'));
              e.target.classList.add('selected');
              memoAnswers.rabbits = e.target.getAttribute('data-val');
              updateMemoOutput();
              
              setTimeout(() => {
                  memoGroup1.classList.remove('active');
                  memoGroup2.classList.add('active');
              }, 400);
          }
      };

      memoGroup2.onclick = (e) => {
          if (e.target.classList.contains('btn-option')) {
              Array.from(memoGroup2.querySelector('.btn-options-container').children).forEach(el => el.classList.remove('selected'));
              e.target.classList.add('selected');
              memoAnswers.math = e.target.getAttribute('data-val');
              updateMemoOutput();
              
              setTimeout(() => {
                  memoGroup2.classList.remove('active');
                  memoGroup3.classList.add('active');
              }, 400);
          }
      };

      memoGroup3.onclick = (e) => {
          const option = e.target.closest('.btn-option');
          if (option) {
              Array.from(memoGroup3.querySelector('.btn-options-container').children).forEach(el => el.classList.remove('selected'));
              option.classList.add('selected');
              memoAnswers.pose = option.getAttribute('data-val');
              updateMemoOutput();
          }
      };

      btnGoToExplanation.onclick = () => {
          navigateToGameScreen(6);
      };
    }

    // --- REINICIAR Y HOOKS ---
    function initGameControls() {
      const btnRestartGame = document.getElementById('btnRestartGame');
      btnRestartGame.onclick = resetGameUI;
    }

    function resetGameUI() {
        gameUserData = {
            mathSelectedNum: null,
            mathResult: 9,
            rabbitsCounted: 6,
            poseSelected: '',
            mathStep: 1
        };
        memoAnswers = {
            rabbits: '',
            math: '',
            pose: ''
        };
        
        // Detener timers
        clearInterval(whackTimerInterval);
        clearTimeout(rabbitTimeout);
        clearInterval(poseTimerInterval);
        whackActive = false;

        // Reset screen 1 UI
        const btnStartWhack = document.getElementById('btnStartWhack');
        const btnGoToScreen2 = document.getElementById('btnGoToScreen2');
        const scoreVal = document.getElementById('scoreVal');
        const whackTimerVal = document.getElementById('whackTimerVal');
        
        if (btnStartWhack) btnStartWhack.style.display = 'inline-block';
        if (btnGoToScreen2) btnGoToScreen2.style.display = 'none';
        if (scoreVal) scoreVal.innerText = '0';
        if (whackTimerVal) whackTimerVal.innerText = '10';
        document.querySelectorAll('#slide-4 .rabbit-target').forEach(r => r.classList.remove('up'));
        
        // Reset screen 2 UI
        const mathSlide1 = document.getElementById('mathSlide1');
        if (mathSlide1) mathSlide1.classList.add('active');
        document.querySelectorAll('#slide-4 .math-slide').forEach(s => {
          if (s.id !== 'mathSlide1') s.classList.remove('active');
        });
        document.querySelectorAll('#slide-4 .btn-math-num').forEach(el => el.classList.remove('selected'));
        
        // Reset screen 4 UI
        const poseButtons = document.getElementById('poseButtons');
        if (poseButtons) {
          Array.from(poseButtons.children).forEach(el => el.classList.remove('selected'));
        }
        
        // Reset screen 5 UI
        const memoGroup1 = document.getElementById('memoGroup1');
        if (memoGroup1) memoGroup1.classList.add('active');
        document.querySelectorAll('#slide-4 .memo-group').forEach(g => {
          if (g.id !== 'memoGroup1') g.classList.remove('active');
        });
        document.querySelectorAll('#slide-4 .memo-group .btn-option').forEach(el => el.classList.remove('selected'));
        
        const memoOutputVal = document.getElementById('memoOutputVal');
        if (memoOutputVal) memoOutputVal.value = '';
        
        const btnGoToExplanation = document.getElementById('btnGoToExplanation');
        if (btnGoToExplanation) btnGoToExplanation.disabled = true;
        
        navigateToGameScreen(1);
    }

    // Sincronización con el cambio de diapositiva
    function onSlideChange(slideIndex) {
      if (slideIndex === 4) {
        // Inicializar DOM del juego y cargarlo
        if (!gameScreens) {
          initGameDOM();
          initWhackGame();
          initMathGame();
          initPoseSelection();
          initMemoTest();
          initGameControls();
        }
        resetGameUI();
      } else {
        // Detener timers activos si salimos de la slide del juego
        whackActive = false;
        clearInterval(whackTimerInterval);
        clearTimeout(rabbitTimeout);
        clearInterval(poseTimerInterval);
      }
    }
  
  

  const rabbitImgData = "data:image/png;base64,";
  document.addEventListener('DOMContentLoaded', () => {
    document.querySelectorAll('.rabbit-target img, .pose-img-box img').forEach(img => {
      if(!img.src || img.src === window.location.href || img.src === '') {
        img.src = rabbitImgData;
      }
    });
  });



window.changeSlide = changeSlide;
window.selectPin = selectPin;
window.adjustValue = adjustValue;
window.calculateCost = calculateCost;
window.closeModal = closeModal;